mapper.select:
select b.id, b.product_id as productId, p.name as productName, p.category_id as categoryId, b.batch_code as batchCode, b.production_time as productionTime, b.expiration_time as expirationTime, b.stock_quantity as stockQuantity, b.locked_quantity as lockedQuantity, b.sold_quantity as soldQuantity, greatest(b.stock_quantity - b.locked_quantity - b.sold_quantity, 0) as availableQuantity, greatest(datediff(b.expiration_time, now()), 0) as daysToExpire, case when b.status = 3 then greatest(b.stock_quantity - b.sold_quantity, 0) else 0 end as wasteQuantity, p.price as basePrice, round( p.price * coalesce(( select pr.discount_rate from pricing_rule pr where pr.status = 1 and greatest(datediff(b.expiration_time, now()), 0) between pr.min_days_to_expire and pr.max_days_to_expire order by pr.priority desc, pr.max_days_to_expire asc limit 1 ), 1.00), 2 ) as currentPrice, b.status from inventory_batch b left join product p on p.id = b.product_id
and ( b.batch_code like concat('%', #{criteria.keyword}, '%') or p.name like concat('%', #{criteria.keyword}, '%') )
and p.category_id = #{criteria.categoryId}
and b.status = #{criteria.status}
and b.status in (1, 2)
and b.status = 0
and b.status = 3
and 1 = 0
and datediff(b.expiration_time, now()) >= #{criteria.expiryDaysMin}
and datediff(b.expiration_time, now()) <= #{criteria.expiryDaysMax}
order by ${criteria.sortColumn} ${criteria.sortDirection}, b.id desc limit #{criteria.limit} offset #{criteria.offset}

